const express = require('express');
const bodyParser = require('body-parser');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(bodyParser.json());

let rewards = {
    1: { scoreThreshold: 100, reward: 'Bronze Medal' },
    2: { scoreThreshold: 200, reward: 'Silver Medal' },
    3: { scoreThreshold: 300, reward: 'Gold Medal' },
};

app.post('/complete-level', (req, res) => {
    const { level, score, time } = req.body;

    if (!level || !score || !time) {
        return res.status(400).json({ message: 'Level, score, and time are required.' });
    }

    const reward = getReward(level, score);
    res.json({ message: 'Level completed!', reward });
});

app.post('/claim-reward', (req, res) => {
    const { userId, reward } = req.body;

    if (!userId || !reward) {
        return res.status(400).json({ message: 'User ID and reward are required.' });
    }

    // Logic to claim reward for user would go here

    res.json({ message: 'Reward claimed successfully!', reward });
});

function getReward(level, score) {
    const levelData = rewards[level];
    if (levelData && score >= levelData.scoreThreshold) {
        return levelData.reward;
    }
    return 'No reward earned';
}

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});